  3	//! Shared domain validation utilities.
  4	
  5	use crate::domain::error::DomainError;
  6	
  7	/// GTS type path prefix required for resource group types.
  8	pub const RG_TYPE_PREFIX: &str = "gts.cf.core.rg.type.v1~";
  9	
 10	/// Validate a GTS type code: non-empty, correct prefix, length limit.
 11	///
 12	/// Input is normalized (trimmed and lowercased) before validation, consistent
 13	/// with [`resource_group_sdk::models::GtsTypePath::new`].
 14	///
 15	/// # Errors
 16	///
 17	/// Returns [`DomainError`] if the code is empty, missing the required prefix, or exceeds 1024 chars.
 18	// @cpt-algo:cpt-cf-resource-group-algo-sdk-foundation-validate-gts-type-path:p1
 19	// @cpt-algo:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1
 20	pub fn validate_type_code(code: &str) -> Result<(), DomainError> {
 21	    let code = code.trim().to_lowercase();
 22	    let code = code.as_str();
 23	    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-1
 24	    if code.is_empty() {
 25	        return Err(DomainError::validation("Type code must not be empty"));
 26	    }
 27	    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-1
 28	    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2
 29	    if !code.starts_with(RG_TYPE_PREFIX) {
 30	        // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2a
 31	        return Err(DomainError::validation(format!(
 32	            "Type code must start with prefix '{RG_TYPE_PREFIX}', got: '{code}'"
 33	        )));
 34	        // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2a
 35	    }
 36	    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2
 37	    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-3
 38	    if code.chars().count() > 1024 {
 39	        return Err(DomainError::validation(
 40	            "Type code must not exceed 1024 characters",
 41	        ));
 42	    }
 43	    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-3
 44	    Ok(())
 45	}
