 47	/// Validate that a `metadata_schema` value is a valid JSON Schema.
 48	///
 49	/// Attempts to compile the schema via `jsonschema::validator_for`. If the value
 50	/// cannot be interpreted as a JSON Schema, returns a [`DomainError::validation`].
 51	///
 52	/// # Errors
 53	///
 54	/// Returns [`DomainError`] if the value is not a valid JSON Schema.
 55	// @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-7
 56	pub fn validate_metadata_schema(schema: &serde_json::Value) -> Result<(), DomainError> {
 57	    jsonschema::validator_for(schema).map_err(|e| {
 58	        DomainError::validation(format!("metadata_schema is not a valid JSON Schema: {e}"))
 59	    })?;
 60	    Ok(())
 61	}
 62	// @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-7
 63	
 64	/// Validate a metadata JSON value against a raw JSON Schema.
 65	///
 66	/// Synchronous counterpart to [`validate_metadata_via_gts`] that does not
 67	/// resolve GTS types. When either `metadata` or `schema` is `None`, the
 68	/// check passes trivially.
 69	///
 70	/// # Errors
 71	///
 72	/// Returns [`DomainError::validation`] when the schema fails to compile
 73	/// or the metadata violates any schema constraint.
 74	pub fn validate_metadata_against_schema(
 75	    metadata: Option<&serde_json::Value>,
 76	    schema: Option<&serde_json::Value>,
 77	) -> Result<(), DomainError> {
 78	    let (Some(metadata), Some(schema)) = (metadata, schema) else {
 79	        return Ok(());
 80	    };
 81	
 82	    let validator = jsonschema::validator_for(schema)
 83	        .map_err(|e| DomainError::validation(format!("metadata_schema is invalid: {e}")))?;
 84	
 85	    let errors: Vec<String> = validator
 86	        .iter_errors(metadata)
 87	        .map(|e| e.to_string())
 88	        .collect();
 89	    if !errors.is_empty() {
 90	        return Err(DomainError::validation(format!(
 91	            "Metadata does not match type schema: {}",
 92	            errors.join("; ")
 93	        )));
 94	    }
 95	    Ok(())
 96	}
 97	
 98	/// Validate a metadata value against a resolved GTS type schema.
 99	///
100	/// Uses `TypesRegistryClient` to fetch the resolved schema (with `allOf`
101	/// composition, `$ref` resolution, and `x-gts-traits` applied), then validates
102	/// the metadata against the resolved schema using `jsonschema`.
103	///
104	/// Returns `Ok(())` when:
105	/// - `metadata` is `None` (nothing to validate)
106	/// - `type_code` has no registered schema in the types registry
107	/// - `metadata` validates against the resolved schema
108	///
109	/// # Errors
110	///
111	/// Returns [`DomainError`] when metadata violates the schema constraints
112	/// or the types registry is unavailable.
113	pub async fn validate_metadata_via_gts(
114	    metadata: Option<&serde_json::Value>,
115	    type_code: &str,
116	    types_registry: &dyn types_registry_sdk::TypesRegistryClient,
117	) -> Result<(), DomainError> {
118	    let Some(metadata) = metadata else {
119	        return Ok(());
120	    };
121	
122	    // Fetch the GTS schema. Local client pre-links ancestors via Arc, so
123	    // `effective_properties()` returns the chain-resolved property map (own
124	    // overrides + inherited).
125	    let schema = match types_registry.get_type_schema(type_code).await {
126	        Ok(schema) => schema,
127	        // No registered schema for this type -- skip metadata validation.
128	        Err(types_registry_sdk::TypesRegistryError::GtsTypeSchemaNotFound(_)) => return Ok(()),
129	        Err(e) => {
130	            return Err(DomainError::validation(format!(
131	                "Failed to resolve GTS type '{type_code}' for metadata validation: {e}"
132	            )));
133	        }
134	    };
135	
136	    // The chained RG type schema may declare `metadata` at any level of
137	    // the inheritance chain — `effective_properties` collects them all.
138	    let merged = schema.effective_properties();
139	    let metadata_schema = merged.get("metadata");
140	
141	    let Some(metadata_schema) = metadata_schema else {
142	        // No metadata property in the schema — any metadata accepted.
143	        return Ok(());
144	    };
145	
146	    let validator = jsonschema::validator_for(metadata_schema)
147	        .map_err(|e| DomainError::validation(format!("Type metadata_schema is invalid: {e}")))?;
148	
149	    let errors: Vec<String> = validator
150	        .iter_errors(metadata)
151	        .map(|e| e.to_string())
152	        .collect();
153	    if !errors.is_empty() {
154	        return Err(DomainError::validation(format!(
155	            "Metadata does not match type schema: {}",
156	            errors.join("; ")
157	        )));
158	    }
159	    Ok(())
160	}
161	// @cpt-end:cpt-cf-resource-group-dod-sdk-foundation-sdk-models:p1:inst-validation-full

