 71	/// TC-TYP-01: Create type with valid allowed_parent_types.
 72	/// Child type created; allowed_parent_types contains parent code;
 73	/// junction rows COUNT = len(allowed_parent_types).
 74	#[tokio::test]
 75	async fn type_create_with_valid_parents() {
 76	    let db = common::test_db().await;
 77	    let type_svc = TypeService::new(db.clone(), Arc::new(TypeRepository));
 78	
 79	    // Create parent type first
 80	    let parent = common::create_root_type(&type_svc, "parent").await;
 81	
 82	    // Create child type with parent in allowed_parent_types
 83	    let child_code = type_code("child");
 84	    let child = type_svc
 85	        .create_type(CreateTypeRequest {
 86	            code: child_code.clone(),
 87	            can_be_root: false,
 88	            allowed_parent_types: vec![parent.code.clone()],
 89	            allowed_membership_types: vec![],
 90	            metadata_schema: None,
 91	        })
 92	        .await
 93	        .expect("create child type");
 94	
 95	    assert_eq!(child.allowed_parent_types, vec![parent.code.clone()]);
 96	    assert!(!child.can_be_root);
 97	
 98	    // DB assertion: junction rows count matches
 99	    let conn = db.conn().expect("get conn");
100	    let scope = system_scope();
101	
102	    let child_model = GtsTypeEntity::find()
103	        .filter(gts_type::Column::SchemaId.eq(&child_code))
104	        .secure()
105	        .scope_with(&scope)
106	        .one(&conn)
107	        .await
108	        .expect("query child type")
109	        .expect("child type exists");
110	
111	    let junction_rows = AllowedParentEntity::find()
112	        .filter(gts_type_allowed_parent::Column::TypeId.eq(child_model.id))
113	        .secure()
114	        .scope_with(&scope)
115	        .all(&conn)
116	        .await
117	        .expect("query junction");
118	
119	    assert_eq!(junction_rows.len(), 1, "Expected 1 junction row");
120	
121	    // Verify parent_type_id is resolved from GTS path to SMALLINT
122	    let parent_model = GtsTypeEntity::find()
123	        .filter(gts_type::Column::SchemaId.eq(&parent.code))
124	        .secure()
125	        .scope_with(&scope)
126	        .one(&conn)
127	        .await
128	        .expect("query parent")
129	        .expect("parent type exists");
130	    assert_eq!(junction_rows[0].parent_type_id, parent_model.id);
131	}
